import string  

# Check lowercase  
def has_lowercase(password):  
    for ch in password:  
        if ch.islower():  
            return True  
    return False  

# Check uppercase  
def has_uppercase(password):  
    for ch in password:  
        if ch.isupper():  
            return True  
    return False  

# Check digits  
def has_digits(password):  
    for ch in password:  
        if ch.isdigit():  
            return True  
    return False  

